### 2. The Actual Functionality - A **Force-Directed Graph Simulation**

```javascript
// Constants
const TAU = 6.283;          // 2π
const PHI = 1.618;          // Golden ratio
const SQRT_HALF = 0.707;    // √(1/2)

// Physics configuration
const config = {
    attraction: 4000,        // Repulsion force between nodes
    frictionCoeff: 0.004,    // Spring default stiffness
    amplification: 0.92,     // Velocity damping factor
    dispersal: 0.0003,       // Centering force
    streamMax: 40,           // Max particles
    streamDecay: 0.04,       // Particle friction
    theta: 0.06              // Camera smoothing factor
};

// Graph nodes (vertices)
const nodes = [
    { id: "alpha",   label: "Alpha",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "beta",    label: "Beta",    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "gamma",   label: "Gamma",   r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "delta",   label: "Delta",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "zeta",    label: "Zeta",    r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Graph edges (springs connecting nodes)
const edges = [
    { a: "alpha", b: "beta",    rest: 160, k: 0.006 },
    { a: "alpha", b: "gamma",   rest: 160, k: 0.005 },
    { a: "alpha", b: "delta",   rest: 170, k: 0.004 },
    { a: "alpha", b: "delta",   rest: 170, k: 0.004 },
    { a: "alpha", b: "epsilon", rest: 180, k: 0.003 },
    { a: "beta",  b: "gamma",   rest: 200, k: 0.002 },
    { a: "delta", b: "zeta",    rest: 220, k: 0.002 },
    { a: "beta",  b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state (current and target)
let camera = { x: 400, y: 300, zoom: 1 };
let cameraTarget = { x: 400, y: 300, zoom: 1 };
```

### 3. Physics Simulation Functions

```javascript
// Main physics step
function simulateForces() {
    // Node-node repulsion (inverse square law, like charged particles)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let dist = Math.sqrt(dx*dx + dy*dy) || 1;
            let force = config.attraction / (dist * dist);
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;
            nodes[i].vx += fx; nodes[i].vy += fy;
            nodes[j].vx -= fx; nodes[j].vy -= fy;
        }
    }

    // Spring forces along edges (Hooke's law)
    for (let i = 0; i < edges.length; i++) {
        let nodeA = findNode(edges[i].a);
        let nodeB = findNode(edges[i].b);
        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx*dx + dy*dy) || 1;
        let displacement = dist - edges[i].rest;
        let force = (edges[i].k || config.frictionCoeff) * displacement;
        // Apply spring forces to both nodes
        nodeA.vx += (dx/dist) * force;
        nodeA.vy += (dy/dist) * force;
        nodeB.vx -= (dx/dist) * force;
        nodeB.vy -= (dy/dist) * force;
    }

    // Integration + damping + centering force
    for (let i = 0; i < nodes.length; i++) {
        nodes[i].vx += (400 - nodes[i].x) * config.dispersal; // center pull X
        nodes[i].vy += (300 - nodes[i].y) * config.dispersal; // center pull Y
        nodes[i].vx *= config.amplification; // damping
        nodes[i].vy *= config.amplification;
        nodes[i].x += nodes[i].vx; // position update
        nodes[i].y += nodes[i].vy;
    }
}

// Spawn particles emanating from random nodes
function spawnParticle() {
    if (particles.length >= config.streamMax) return;
    let node = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * TAU;
    let speed = 0.3 + Math.random() * SQRT_HALF;
    particles.push({
        x: node.x, y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT_HALF
    });
}

// Update particles (move, age, remove dead ones)
function updateParticles() {
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];
        p.vx *= 1 - config.streamDecay * 0.125;
        p.vy *= 1 - config.streamDecay * 0.125;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera interpolation
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.theta;
    camera.y += (cameraTarget.y - camera.y) * config.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// Main loop (runs every 16ms ≈ 60fps)
function tick() {
    simulateForces();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle(); // spawn particle every 3rd frame
    frameCount++;
}
setInterval(tick, 16);
```

## Summary

This is a **force-directed graph layout engine** with particle effects, wrapped in heavy obfuscation and **domain-locked to `keleith.com`**. It:

1. **Simulates 6 nodes** (Alpha, Beta, Gamma, Delta, Zeta, Epsilon) connected by spring-like edges
2. **Uses physics**: repulsion between all nodes + spring attraction along edges + centering force + velocity damping
3. **Spawns decorative particles** that emanate from random nodes and slowly fade
4. **Smoothly interpolates a camera** toward a target position
5. **Protects itself** with anti-debugging, anti-tampering, and domain-checking (redirects to `https://keleith.com` if run elsewhere)

The code is **computation only** — there's no rendering/drawing code here, suggesting it's paired with a separate rendering module (likely Canvas or WebGL) that reads the node/particle positions.
